class Decoder{initAudioContext(t){this.audioCtx=new AudioContext({latencyHint:"playback",sampleRate:t})}constructor(){this.audioCtx=null;try{this.initAudioContext(3e3)}catch(t){this.initAudioContext(8e3)}}async decode(t){if(this.audioCtx)return this.audioCtx.decodeAudioData(t);throw new Error("AudioContext is not initialized")}createBuffer(e,t){if((e="number"==typeof e[0]?[e]:e)[0].some(t=>1<t||t<-1)){const o=Math.max(...e[0]);e=e.map(t=>t.map(t=>t/o))}return{length:e[0].length,duration:t,numberOfChannels:e.length,sampleRate:e[0].length/t,getChannelData:t=>e?.[t],copyFromChannel:AudioBuffer.prototype.copyFromChannel,copyToChannel:AudioBuffer.prototype.copyToChannel}}destroy(){this.audioCtx?.close(),this.audioCtx=null}}export default Decoder;